module TopModule (
    input wire clk,
    input wire reset,
    input wire start,
    input wire [3:0] node_in,
    output reg [3:0] current_node,
    output reg done
);
    reg [3:0] stack [0:15];
    reg [3:0] sp;
    reg [3:0] state;
    parameter IDLE = 0, PROCESS = 1, COMPLETE = 2;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            sp <= 0;
            current_node <= 4'b0000;
            done <= 0;
            state <= IDLE;
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        stack[sp] <= node_in;
                        sp <= sp + 1;
                        state <= PROCESS;
                    end
                end
                PROCESS: begin
                    if (sp > 0) begin
                        sp <= sp - 1;
                        current_node <= stack[sp];
                    end else begin
                        state <= COMPLETE;
                    end
                end
                COMPLETE: begin
                    done <= 1;
                    state <= IDLE;
                end
            endcase
        end
    end
endmodule

